2036 /// Perform multiple-use aware simplfications for fabs(\p Src). Returns a
2037 /// replacement value if it's simplified, otherwise nullptr. Updates \p Known
2038 /// with the known fpclass if not simplified.
2039 static Value *simplifyDemandedFPClassFabs(KnownFPClass &Known, Value *Src,
2040                                           FPClassTest DemandedMask,
2041                                           KnownFPClass KnownSrc, bool NSZ) {
2042   if ((DemandedMask & fcNan) == fcNone)
2043     KnownSrc.knownNot(fcNan);
2044   if ((DemandedMask & fcInf) == fcNone)
2045     KnownSrc.knownNot(fcInf);
2046 
2047   if (KnownSrc.SignBit == false ||
2048       ((DemandedMask & fcNan) == fcNone && KnownSrc.isKnownNever(fcNegative)))
2049     return Src;
2050 
2051   // If the only sign bit difference is due to -0, ignore it with nsz
2052   if (NSZ &&
2053       KnownSrc.isKnownNever(KnownFPClass::OrderedLessThanZeroMask | fcNan))
2054     return Src;
2055 
2056   Known = KnownFPClass::fabs(KnownSrc);
2057   return nullptr;
2058 }
