3107 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3108                                                FPClassTest DemandedMask,
3109                                                KnownFPClass &Known,
3110                                                unsigned Depth) {
3111   Use &U = I->getOperandUse(OpNo);
3112   Value *V = U.get();
3113   Type *VTy = V->getType();
3114 
3115   if (DemandedMask == fcNone) {
3116     if (isa<UndefValue>(V))
3117       return false;
3118     replaceUse(U, PoisonValue::get(VTy));
3119     return true;
3120   }
3121 
3122   // Handle constant
3123   Instruction *VInst = dyn_cast<Instruction>(V);
3124   if (!VInst) {
3125     // Handle constants and arguments
3126     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3127 
3128     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
3129     if (ValidResults == fcNone) {
3130       if (isa<UndefValue>(V))
3131         return false;
3132       replaceUse(U, PoisonValue::get(VTy));
3133       return true;
3134     }
3135 
3136     // Do not try to replace values which are already constants (unless we are
3137     // folding to poison). Doing so could promote poison elements to non-poison
3138     // constants.
3139     if (isa<Constant>(V))
3140       return false;
3141 
3142     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
3143     if (!FoldedToConst || FoldedToConst == V)
3144       return false;
3145 
3146     replaceUse(U, FoldedToConst);
3147     return true;
3148   }
3149 
3150   if (Depth == MaxAnalysisRecursionDepth)
3151     return false;
3152 
3153   Value *NewVal;
3154 
3155   if (VInst->hasOneUse()) {
3156     // If the instruction has one use, we can directly simplify it.
3157     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3158   } else {
3159     // If there are multiple uses of this instruction, then we can simplify
3160     // VInst to some other value, but not modify the instruction.
3161     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3162                                                 Depth);
3163   }
3164 
3165   if (!NewVal)
3166     return false;
3167   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3168     salvageDebugInfo(*OpInst);
3169 
3170   replaceUse(U, NewVal);
3171   return true;
3172 }
