4214   }
4215 
4216   SmallVector<Value *> Changed;
4217   if (handleUnreachableTerminator(BB->getTerminator(), Changed)) {
4218     MadeIRChange = true;
4219     for (Value *V : Changed)
4220       addToWorklist(cast<Instruction>(V));
4221   }
4222 
4223   // Handle potentially dead successors.
4224   for (BasicBlock *Succ : successors(BB))
